import asyncio, aiohttp, json, time, ssl, random
from collections import defaultdict
from datetime import datetime, timezone

API='https://api.ivxholding.com'
SB='https://kvclcdjmjghndxsngfzb.supabase.co'
AK='eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imt2Y2xjZGptamdobmR4c25nZnpiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzMxOTQwMjcsImV4cCI6MjA4ODc3MDAyN30.OLDwa21VHQNs151AD-8k--_HigQ2d-N7yJfFn5UeNPk'
OE='iperez4242@gmail.com'
OP='X146corp@1x146corp\$\$1'
def ts(): return datetime.now(timezone.utc).strftime('%H:%M:%SZ')
def pct(sl,p): return sl[min(int(len(sl)*p/100),len(sl)-1)] if sl else 0

class R:
    def __init__(s,n,u,d):
        s.n=n;s.u=u;s.d=d;s.lat=[];s.err=0;s.codes=defaultdict(int)
        s.tot=0;s.start=None;s.end=None;s.aborted=False;s.reason=None;s.to=0
    @property
    def rps(s):
        e=(s.end-s.start) if s.end and s.start else 0
        return s.tot/e if e>0 else 0
    @property
    def er(s): return s.err/s.tot if s.tot>0 else 0
    def sum(s):
        ls=sorted(s.lat)
        return {'level':s.n,'users':s.u,'total':s.tot,'rps':round(s.rps,1),
                'errors':s.err,'err_pct':round(s.er*100,2),
                'p50':round(pct(ls,50),1),'p95':round(pct(ls,95),1),'p99':round(pct(ls,99),1),
                'min':round(ls[0],1) if ls else 0,'max':round(ls[-1],1) if ls else 0,
                'timeouts':s.to,'codes':dict(s.codes),'aborted':s.aborted,'reason':s.reason}

MIX={'health':10,'version':5,'readiness':5,'login':8,'feed':15,'rooms':10,
     'sb_read':10,'chat':8,'protected':10,'sb_table':10,'diag':5,'msgs':4}

async def wk(sess,wid,tok,stop,res):
    ah={'Authorization':f'Bearer {tok}','Content-Type':'application/json'}
    sh={'apikey':AK}
    while not stop.is_set() and not res.aborted:
        act=random.choices(list(MIX.keys()),weights=list(MIX.values()),k=1)[0]
        try:
            s=time.time();st=0
            if act=='health': async with sess.get(f'{API}/health',timeout=aiohttp.ClientTimeout(total=10)) as r: st=r.status;await r.read()
            elif act=='version': async with sess.get(f'{API}/version',timeout=aiohttp.ClientTimeout(total=10)) as r: st=r.status;await r.read()
            elif act=='readiness': async with sess.get(f'{API}/readiness',timeout=aiohttp.ClientTimeout(total=10)) as r: st=r.status;await r.read()
            elif act=='login': async with sess.post(f'{SB}/auth/v1/token?grant_type=password',json={'email':OE,'password':OP},headers={'apikey':AK,'Content-Type':'application/json'},timeout=aiohttp.ClientTimeout(total=15)) as r: st=r.status;await r.read()
            elif act=='feed': async with sess.get(f'{API}/api/public/messages?limit=20',headers=ah,timeout=aiohttp.ClientTimeout(total=10)) as r: st=r.status;await r.read()
            elif act=='msgs': async with sess.get(f'{API}/messages?limit=20',headers=ah,timeout=aiohttp.ClientTimeout(total=10)) as r: st=r.status;await r.read()
            elif act=='rooms': async with sess.get(f'{API}/api/public/rooms',headers=ah,timeout=aiohttp.ClientTimeout(total=10)) as r: st=r.status;await r.read()
            elif act=='sb_read': async with sess.get(f'{SB}/rest/v1/ivx_conversations?select=*&limit=10',headers={**sh,'Authorization':f'Bearer {tok}'},timeout=aiohttp.ClientTimeout(total=10)) as r: st=r.status;await r.read()
            elif act=='chat': async with sess.post(f'{API}/api/public/send-message',json={'room':'main-room','content':f'lt-{wid}-{int(time.time())}'},headers=ah,timeout=aiohttp.ClientTimeout(total=10)) as r: st=r.status;await r.read()
            elif act=='protected': async with sess.get(f'{API}/api/ivx/owner-dashboard',timeout=aiohttp.ClientTimeout(total=10)) as r: st=r.status;await r.read()
            elif act=='sb_table':
                t=random.choice(['landing_submissions','team_members','push_tokens','referrals'])
                async with sess.get(f'{SB}/rest/v1/{t}?select=*&limit=5',headers={**sh,'Authorization':f'Bearer {tok}'},timeout=aiohttp.ClientTimeout(total=10)) as r: st=r.status;await r.read()
            elif act=='diag': async with sess.get(f'{API}/diagnostics',headers=ah,timeout=aiohttp.ClientTimeout(total=10)) as r: st=r.status;await r.read()
            el=(time.time()-s)*1000;res.lat.append(el);res.tot+=1;res.codes[st]+=1
            if st>=500: res.err+=1
            elif st>=400 and act!='protected': res.err+=1
            if res.tot>50 and res.er>0.05: res.aborted=True;res.reason='err>5%'
        except asyncio.TimeoutError: res.tot+=1;res.err+=1;res.codes[0]+=1;res.to+=1
        except: res.tot+=1;res.err+=1;res.codes[-1]+=1
        await asyncio.sleep(random.uniform(0.1,0.3))

async def lvl(sess,name,users,dur,tok):
    r=R(name,users,dur);r.start=time.time();stop=asyncio.Event()
    ws=[asyncio.create_task(wk(sess,i,tok,stop,r)) for i in range(users)]
    await asyncio.sleep(dur);stop.set()
    try: await asyncio.wait_for(asyncio.gather(*ws,return_exceptions=True),timeout=10)
    except: pass
    r.end=time.time();s=r.sum()
    status='ABORT' if s['aborted'] else 'OK'
    print(f'{s[\"level\"]:>8} {s[\"users\"]:>6}u {s[\"rps\"]:>7.1f}rps p50={s[\"p50\"]:>6.0f}ms p95={s[\"p95\"]:>6.0f}ms p99={s[\"p99\"]:>6.0f}ms err={s[\"errors\"]:>5}({s[\"err_pct\"]}%) to={s[\"timeouts\"]:>3} {status}',flush=True)
    return r

async def main():
    print(f'=== PHASE 2: PROGRESSIVE LOAD ({ts()}) ===',flush=True)
    sc=ssl.create_default_context();sc.check_hostname=False;sc.verify_mode=ssl.CERT_NONE
    c=aiohttp.TCPConnector(limit=3000,limit_per_host=3000,ssl=sc,enable_cleanup_closed=True)
    async with aiohttp.ClientSession(connector=c,timeout=aiohttp.ClientTimeout(total=60)) as sess:
        async with sess.post(f'{SB}/auth/v1/token?grant_type=password',json={'email':OE,'password':OP},headers={'apikey':AK,'Content-Type':'application/json'},timeout=aiohttp.ClientTimeout(total=15)) as r:
            tok=(await r.json()).get('access_token')
        print(f'Auth OK (len={len(tok)})',flush=True)
        results=[];first_fail=None
        for name,u,d in [('L10',10,4),('L25',25,4),('L50',50,4),('L100',100,3),('L250',250,3),('L500',500,3),('L1000',1000,3),('L2500',2500,2),('L5000',5000,2),('L10000',10000,2)]:
            r=await lvl(sess,name,u,d,tok)
            results.append(r.sum())
            if r.aborted:
                print(f'STOP at {u}u: {r.reason}',flush=True)
                first_fail=u;break
            await asyncio.sleep(1)
        with open('/tmp/ivx_p2.json','w') as f: json.dump({'results':results,'first_fail':first_fail},f,indent=2)
        print(f'Phase 2 done: {len(results)} levels tested, first_fail={first_fail}',flush=True)

asyncio.run(main())
" 2>&1

